// Some portions generated by Co-Pilot
"use client";

import React, { useEffect, useState } from "react";
import { useTranslations } from "next-intl";

interface TocItem {
  id: string;
  text: string;
  level: number;
}

const DocTableOfContents: React.FC = () => {
  const [headings, setHeadings] = useState<TocItem[]>([]);
  const [activeId, setActiveId] = useState<string>("");
  const t = useTranslations("DocTableOfContents");

  useEffect(() => {
    const article = document.querySelector("[role='article']");
    if (!article) return;

    const elements = article.querySelectorAll("h2[id], h3[id]");
    const items: TocItem[] = Array.from(elements).map((el) => ({
      id: el.id,
      text: el.textContent?.replace(/^#\s*/, "") || "",
      level: el.tagName === "H2" ? 2 : 3,
    }));
    setHeadings(items);
  }, []);

  useEffect(() => {
    if (headings.length === 0) return;

    const observer = new IntersectionObserver(
      (entries) => {
        // Find the first visible heading
        const visible = entries.find((e) => e.isIntersecting);
        if (visible?.target.id) {
          setActiveId(visible.target.id);
        }
      },
      { rootMargin: "-80px 0px -70% 0px", threshold: 0 },
    );

    headings.forEach(({ id }) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, [headings]);

  if (headings.length === 0) return null;

  return (
    <nav aria-label={t("on-this-page")}>
      <h4 className="text-xs font-semibold uppercase tracking-wider text-gray-400 light:text-gray-500 mb-3">
        {t("on-this-page")}
      </h4>
      <ul className="space-y-1 text-sm">
        {headings.map((heading) => (
          <li key={heading.id}>
            <a
              href={`#${heading.id}`}
              className={`block py-1 transition-colors duration-150 border-l-2 ${
                heading.level === 3 ? "pl-5" : "pl-3"
              } ${
                activeId === heading.id
                  ? "border-pink text-pink"
                  : "border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-600 light:text-gray-500 light:hover:text-gray-900"
              }`}
            >
              {heading.text}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default DocTableOfContents;
